import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"百世诗篇","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/2.社交类/百世诗篇.md","filePath":"4.资源分区/1.血统与训练/2.社交类/百世诗篇.md"}'),o={name:"4.资源分区/1.血统与训练/2.社交类/百世诗篇.md"};function d(p,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"百世诗篇",tabindex:"-1"},[n("百世诗篇 "),r("a",{class:"header-anchor",href:"#百世诗篇","aria-label":'Permalink to "百世诗篇"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌036")])])],-1),s('<h1 id="百世诗篇-1" tabindex="-1">百世诗篇 <a class="header-anchor" href="#百世诗篇-1" aria-label="Permalink to &quot;百世诗篇&quot;">​</a></h1><p>训练：百世诗篇<br> 心之所之谓之志。心有所之，必形于言，故曰诗言志。<br> 诸界万方，固有森严而无存遐想，万物周转有序之世界，亦有烂漫华丽，天地自有爱恨情仇之世界。<br> 后者中，武者有内气，血气，劲力，排山崩岳；道家，能修个飞升仙界，逍遥自在；和尚，亦能够晓他个今生来世，苦海超脱；<br> 然诗人，苦苦求索，以文字成百世流传之华章，用心志书写世事人心，安能不在一方世界有种种圆满之想象?<br> 百世诗篇，即为录此以诗入道世界之奥秘，传轮回之人以欣赏。</p><p>D级：诵诗得意<br> 价格：D+600<br> 描述：你初入诗界修行之门。此方世界，诗歌乃真正具有天地奥妙之物，凡俗之人，需要通过诵读诗中真意，从而生出才气，进而有超越凡俗之契机。<br> 【才气】：你开启一个新能量池，名为“才气”，关键属性为决心+风度。才气视为灵气能量池的一个变体。只要你没有陷入昏迷的状态，那么你眼能观看天地景观，耳能听生灵自然声响，心能思人生种种体悟，才气就不会断绝。<br> 无需任何行动，你的才气即可以每小时决心/6点的速度恢复。必要时你可以用诵读诗篇或是创作诗篇的方式激发自身的才气，当你进行一次短休息时，你可以做出符合画风的演出，从而恢复风度/6点才气。才气一日的恢复上限为能量池上限的三倍。 <br> 现在你获得了才气的基本用法：你可以在进行任何心智属性相关检定时，消耗2点才气，获得2dp的能量加值。<br> 【诗剑】：诗界之中，魍魉自人心中种种恶念之中滋生，为祸人间，拥有种种妖法。为对抗魍魉，诗人得诗意而成剑形，以心志铸剑，斩杀魍魉。<br> 现在，你获得一种新的攻击方式，名为“驭使诗剑”。这一攻击方式仅能在持有被称为“诗剑”的武器进行攻击时才能使用。<br> “驭使诗剑”的攻击构成为：决心+表达+专业：诗歌+辅助专业：剑（注：即武技技能下属的专业：剑）。“驭使诗剑”具有15米的射程，造成的伤害类型为精神伤害，并且具有【法破】特性。</p><p>C级：诗心初成<br> 价格：C+1200<br> 描述：以诗歌真意凝入心志，你的精神变得更为坚韧强大，而以诗心驾驭诗剑，也能够变得事半功倍。<br> 【诗心】：以诗道润人心，成就感应天地，得见本性之诗心。<br> 诗心能够助诗人守护本性，不为外魔所污。从现在开始，只要你的才气能量池不为空，你具有C级的针对影响心灵效果的免疫。<br> 诗心的形成也强化了才气蕴养心神的效果。现在你使用才气基本用法之时，可以追加投入1点才气，使得获得的能量加值改为4点。<br> 你现在能够以诗心驾驭诗剑，得心应手，神妙倍增。你现在以诗剑进行的攻击具有【9加骰】。</p><p>B级：诗心化象<br> 价格：B+2400<br> 描述：你对于诗心的理解更进一步，才气以你心为体察万物之目，习得世界运转之理，能够显化而出，成万象之状。<br> 【化象】：一步虚实渺，一念万般生。<br> 现在，只要你的才气能量池不为空，你从C级训练获得的针对影响心灵效果的免疫的等级提升到B级。现在你以诗剑进行的攻击改为具有【8加骰】。<br> 现在你在使用才气基本用法之时，可以在使用了C级的追加投入才气效果之后，再将投入的才气翻倍（即提升到6点），再在以心智属性进行的检定中获得1点附加成功。<br> 现在你可以花费一个移动动作和4点才气启动“诗心化象”，“诗心化象”每轮需要以一个移动动作和6点才气进行维持。<br> 在诗心化象开启期间，你具有B级别的幻象来源的反侦测效果。这在画风上表现为你可以用诗心显化的幻象迷惑敌人，令对方无法察觉到你的本体所在。<br> 同时你在开启期间，能够与周遭天地以诗心相通，从而自由地随你心意凝聚种种幻象。这些幻象栩栩如生，并且可以随你心意行动，但是你现在还没有达到自虚空演实物的境界，当其他人触碰到这些幻象之时，就会发现这些幻象并无实体。这是一个B级别的环境来源的幻象效果。<br> 在诗心化象开启期间，你沟通天地，显化种种神妙，也使得你的诗剑之术更具威力。<br> 现在你将才气的基础用法用于以诗剑的攻击进行增益时，获得的能量加值与附加成功翻倍。</p><p>A级：诗华为魂<br> 价格：A+4800<br> 描述：诗者之心，可跨百世光阴。现在你的诗心已能与千古诗篇共鸣，引动前辈先贤留于诗中的一点真灵，激发诗剑的真正威力，让“诗魂”显化而出，与你并肩作战。<br> 【诗魂】：现在，你可以用一个自由动作呼唤诗剑之中蕴藏的诗魂。诗魂显现时，诗剑光华大放，仿佛有先贤虚影持剑而立，与你身影重合。<br> 你获得各诗剑中记述的诗魂显现之时的增益。并且,在诗魂显现之时，你额外获得8AP，这8AP只能用于以诗剑进行攻击，或者是施展诗剑下属的技艺，这在画风上表现为诗魂出击，与传承诗魂的后辈一同夹击敌人。<br> 现在，只要你的才气能量池不为空，你从C级训练获得的针对影响心灵效果的免疫的等级提升到A级。<br> 现在，你在为一次决心相关检定运用才气的基础用法时，可以在运用了B级的获取附加成功效果的基础上，将投入的才气再进行一次翻倍（即6才气翻倍为12才气），使得你进行的这次检定的出目变为1.5倍。这个效果一轮只能使用一次。<br> 同时现在当诗魂显现之时，你如果施展“诗心化象”，则你获得的反侦测效果的等级将提升到A级。你获得幻象的效果也提升到A级，这将使得你生成的幻象具有实体，不过如果有人对幻象进行攻击，则可以将幻象击溃，令其化为才气四散。<br> 【千古未绝】:诗之声，诗之意，诗之神，千载茫茫不能磨灭，万里异域仍可动心。<br> 现在，只要你的才气能量池不为空，你具有A级别的针对时空来源效果的免疫，只要你的意志池不为空，你就始终具有S级别的免疫即死效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const A=a(o,[["render",d]]);export{f as __pageData,A as default};
